// Input validation and sanitization
function sanitizeInput(str) {
  if (typeof str !== 'string') return '';
  // Remove any null bytes and limit length
  return str.replace(/\0/g, '').substring(0, 256);
}

// API Key Authentication Middleware
function authenticateApiKey(req, res, next) {
  // Accept API key from header (preferred) or query parameter
  let apiKey = req.headers['x-api-key'] || req.query.api_key;

  if (!apiKey) {
    console.log('[AUTH_FAIL]', JSON.stringify({
      timestamp: new Date().toISOString(),
      requestId: req.requestId,
      reason: 'missing_api_key',
      ip: req.ip
    }));
    return res.status(401).json({
      error: 'Unauthorized',
      message: 'API key is required. Provide via X-API-Key header or api_key query parameter.'
    });
  }

  apiKey = sanitizeInput(apiKey);

  // Validate API key format before checking
  if (apiKey.length < 10 || apiKey.length > 128) {
    console.log('[AUTH_FAIL]', JSON.stringify({
      timestamp: new Date().toISOString(),
      requestId: req.requestId,
      reason: 'invalid_key_format',
      ip: req.ip
    }));
    return res.status(401).json({
      error: 'Unauthorized',
      message: 'Invalid API key format.'
    });
  }

  // Use constant-time comparison via hashed lookup
  const hashedKey = hashApiKey(apiKey);
  const keyData = validApiKeys.get(hashedKey);

  if (!keyData) {
    console.log('[AUTH_FAIL]', JSON.stringify({
      timestamp: new Date().toISOString(),
      requestId: req.requestId,
      reason: 'invalid_api_key',
      apiKeyMasked: maskApiKey(apiKey),
      ip: req.ip
    }));
    return res.status(403).json({
      error: 'Forbidden',
      message: 'Invalid API key.'
    });
  }

  // Attach key metadata to request (NOT the key itself)
  req.apiKeyOwner = keyData.owner;
  req.apiKeyPermissions = keyData.permissions;

  // Remove API key from query parameters to prevent downstream leakage
  delete req.query.api_key;

  // Remove API key from URL to prevent logging by downstream services
  if (req.url.includes('api_key=')) {
    const url = new URL(req.url, `http://${req.headers.host}`);
    url.searchParams.delete('api_key');
    req.url = url.pathname + url.search;
  }

  console.log('[AUTH_SUCCESS]', JSON.stringify({
    timestamp: new Date().toISOString(),
    requestId: req.requestId,
    owner: keyData.owner,
    apiKeyMasked: maskApiKey(apiKey),
  }));

  next();
}

